import{_ as a,o as t,c as d,a2 as o}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"API de imagen aleatoria y galería pública","description":"","frontmatter":{},"headers":[],"relativePath":"es/Other/random-image-api-and-public-gallery.md","filePath":"es/Other/random-image-api-and-public-gallery.md","lastUpdated":1781962217000}'),i={name:"es/Other/random-image-api-and-public-gallery.md"};function r(s,e,c,l,n,p){return t(),d("div",null,[...e[0]||(e[0]=[o(`<h1 id="api-de-imagen-aleatoria-y-galeria-publica" tabindex="-1">API de imagen aleatoria y galería pública <a class="header-anchor" href="#api-de-imagen-aleatoria-y-galeria-publica" aria-label="Permalink to &quot;API de imagen aleatoria y galería pública&quot;">​</a></h1><p>Ambas funciones se configuran en:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Configuración del sistema -&gt; Otros ajustes</span></span></code></pre></div><h2 id="api-de-imagen-aleatoria" tabindex="-1">API de imagen aleatoria <a class="header-anchor" href="#api-de-imagen-aleatoria" aria-label="Permalink to &quot;API de imagen aleatoria&quot;">​</a></h2><p>La API de imagen aleatoria toma un archivo al azar desde los directorios indicados. Sirve para fondos de sitio, rotación de avatares o llamadas externas a imágenes aleatorias.</p><p>Una vez activada, se puede usar:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://tu-dominio/random</span></span></code></pre></div><h2 id="ajustes-de-la-api" tabindex="-1">Ajustes de la API <a class="header-anchor" href="#ajustes-de-la-api" aria-label="Permalink to &quot;Ajustes de la API&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Opción</th><th>Descripción</th></tr></thead><tbody><tr><td>Habilitar</td><td>Activa o desactiva <code>/random</code>; si está desactivada, se deniega el acceso</td></tr><tr><td>Directorios</td><td>Limita de qué directorios se pueden tomar archivos</td></tr><tr><td>Ejemplo de llamada</td><td>Genera un enlace de API listo para copiar</td></tr></tbody></table><p>Puedes seleccionar varios directorios. Si solo permites <code>/landscape/</code> y <code>/portrait/</code>, la API solo elegirá archivos dentro de esos directorios o sus subdirectorios.</p><h2 id="parametros-principales" tabindex="-1">Parámetros principales <a class="header-anchor" href="#parametros-principales" aria-label="Permalink to &quot;Parámetros principales&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Parámetro</th><th>Ejemplo</th><th>Descripción</th></tr></thead><tbody><tr><td><code>dir</code></td><td><code>/landscape/</code></td><td>Directorio objetivo</td></tr><tr><td><code>content</code></td><td><code>image</code></td><td>Tipo de medio: <code>image</code>, <code>video</code>, <code>audio</code> o combinación con comas</td></tr><tr><td><code>orientation</code></td><td><code>auto</code></td><td><code>portrait</code>, <code>landscape</code> o <code>auto</code></td></tr><tr><td><code>type</code></td><td><code>url</code></td><td>Vacío redirige; <code>url</code> devuelve texto; <code>json</code> devuelve JSON</td></tr><tr><td><code>origin</code></td><td><code>1</code></td><td>Con <code>type=url</code>, devuelve enlace completo</td></tr><tr><td><code>age</code></td><td><code>all-ages,r12</code></td><td>Filtra por clasificación de edad</td></tr><tr><td><code>tag</code></td><td><code>wallpaper,sky</code></td><td>Solo archivos que contienen esas etiquetas</td></tr><tr><td><code>ex</code></td><td><code>private</code></td><td>Excluye archivos con esas etiquetas</td></tr></tbody></table><h2 id="formatos-de-respuesta" tabindex="-1">Formatos de respuesta <a class="header-anchor" href="#formatos-de-respuesta" aria-label="Permalink to &quot;Formatos de respuesta&quot;">​</a></h2><p>Sin <code>type</code>, la API redirige directamente al archivo aleatorio.</p><p><code>type=url</code> devuelve un enlace en texto plano.</p><p><code>type=json</code> devuelve información del archivo: enlace, ID, nombre, tipo, etiquetas, clasificación y más.</p><h2 id="restricciones-de-acceso" tabindex="-1">Restricciones de acceso <a class="header-anchor" href="#restricciones-de-acceso" aria-label="Permalink to &quot;Restricciones de acceso&quot;">​</a></h2><p>La API respeta las reglas públicas configuradas en el panel.</p><table tabindex="0"><thead><tr><th>Regla</th><th>Efecto</th></tr></thead><tbody><tr><td>Límite de directorios</td><td>Solo elige archivos en directorios permitidos</td></tr><tr><td>Lista negra</td><td>Los archivos bloqueados no entran en el conjunto aleatorio</td></tr><tr><td>Modo lista blanca</td><td>Solo devuelve archivos permitidos explícitamente</td></tr><tr><td>Clasificación de edad</td><td>Filtra R12, R16, R18 según el modo de acceso</td></tr></tbody></table><p>Si no hay archivos que cumplan los filtros, devolverá que no hay resultados.</p><h2 id="galeria-publica" tabindex="-1">Galería pública <a class="header-anchor" href="#galeria-publica" aria-label="Permalink to &quot;Galería pública&quot;">​</a></h2><p>La galería pública ofrece una página de solo lectura para que los visitantes vean los directorios que permites publicar.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://tu-dominio/browse/nombre-del-directorio</span></span></code></pre></div><h2 id="ajustes-de-galeria" tabindex="-1">Ajustes de galería <a class="header-anchor" href="#ajustes-de-galeria" aria-label="Permalink to &quot;Ajustes de galería&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Opción</th><th>Descripción</th></tr></thead><tbody><tr><td>Habilitar</td><td>Activa o desactiva la galería pública</td></tr><tr><td>Modo de carga de imágenes</td><td>Decide si se usan originales o miniaturas</td></tr><tr><td>Directorios públicos</td><td>Define qué directorios pueden ver los visitantes</td></tr></tbody></table><p>Ejemplo:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/,/2/,/landscape/,/portrait/</span></span></code></pre></div><p>Con esa configuración, los visitantes podrán abrir:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://tu-dominio/browse/1</span></span>
<span class="line"><span>https://tu-dominio/browse/2</span></span>
<span class="line"><span>https://tu-dominio/browse/landscape</span></span>
<span class="line"><span>https://tu-dominio/browse/portrait</span></span></code></pre></div><p>Los directorios no publicados serán rechazados.</p><h2 id="que-permite-la-galeria" tabindex="-1">Qué permite la galería <a class="header-anchor" href="#que-permite-la-galeria" aria-label="Permalink to &quot;Qué permite la galería&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Función</th><th>Descripción</th></tr></thead><tbody><tr><td>Explorar directorios</td><td>Ver archivos y subdirectorios publicados</td></tr><tr><td>Buscar</td><td>Buscar por nombre, ID de archivo o etiqueta</td></tr><tr><td>Filtrar por tipo</td><td>Imagen, vídeo, audio u otros archivos</td></tr><tr><td>Filtrar por etiqueta</td><td>Incluir o excluir etiquetas</td></tr><tr><td>Filtrar por orientación</td><td>Horizontal, vertical u otros criterios</td></tr><tr><td>Copiar enlace</td><td>Copiar el enlace público del archivo</td></tr><tr><td>Previsualizar medios</td><td>Ver imágenes, vídeos y audio en la página</td></tr></tbody></table>`,32)])])}const b=a(i,[["render",r]]);export{h as __pageData,b as default};
